import React, { useEffect, useMemo, useRef, useState } from 'react';
import AssetStateForm from './AssetStateForm';
import useResizableColumns from './useResizableColumns';
import { AssetState, deleteAssetState, getAssetStates } from '../services/api';

const filterOptions = ['Active Asset States', 'All Asset States'];
const columnFilterOptions = ['Contains', 'Does not contain', 'Equals', 'Does not equal', 'Begins with', 'Ends with', 'Blank', 'Not blank'] as const;

type ColumnField = 'name' | 'description' | 'requires_ownership' | 'requires_scan' | 'active';
type ColumnFilterOperator = (typeof columnFilterOptions)[number];
type SortDirection = 'asc' | 'desc';
type ColumnFilter = { operator: ColumnFilterOperator; value: string };

const allColumns = [
  { field: 'name' as ColumnField, label: 'Name' },
  { field: 'description' as ColumnField, label: 'Description' },
  { field: 'requires_ownership' as ColumnField, label: 'Requires Ownership' },
  { field: 'requires_scan' as ColumnField, label: 'Requires Scan' },
  { field: 'active' as ColumnField, label: 'Active' },
];

const defaultColumnWidths: Record<ColumnField, number> = {
  name: 250,
  description: 320,
  requires_ownership: 250,
  requires_scan: 240,
  active: 220,
};

const defaultColumnFilter: ColumnFilter = { operator: 'Contains', value: '' };

const getColumnValue = (item: AssetState, field: ColumnField) => {
  if (field === 'requires_ownership') return item.requires_ownership ? 'Yes' : 'No';
  if (field === 'requires_scan') return item.requires_scan ? 'Yes' : 'No';
  if (field === 'active') return item.active ? 'Yes' : 'No';
  return item[field] ?? '';
};

const doesValueMatchColumnFilter = (rawValue: string, filter: ColumnFilter) => {
  const value = rawValue.trim().toLowerCase();
  const filterValue = filter.value.trim().toLowerCase();
  if (filter.operator === 'Blank') return value.length === 0;
  if (filter.operator === 'Not blank') return value.length > 0;
  if (!filterValue) return true;

  switch (filter.operator) {
    case 'Contains':
      return value.includes(filterValue);
    case 'Does not contain':
      return !value.includes(filterValue);
    case 'Equals':
      return value === filterValue;
    case 'Does not equal':
      return value !== filterValue;
    case 'Begins with':
      return value.startsWith(filterValue);
    case 'Ends with':
      return value.endsWith(filterValue);
    default:
      return true;
  }
};

const AssetStateTable: React.FC = () => {
  const [assetStates, setAssetStates] = useState<AssetState[]>([]);
  const [open, setOpen] = useState(false);
  const [editing, setEditing] = useState<AssetState | null>(null);
  const [activeFilter, setActiveFilter] = useState(filterOptions[0]);
  const [actionAnchorEl, setActionAnchorEl] = useState<HTMLElement | null>(null);
  const [actionRow, setActionRow] = useState<AssetState | null>(null);
  const [columnsAnchorEl, setColumnsAnchorEl] = useState<HTMLElement | null>(null);
  const [visibleColumns, setVisibleColumns] = useState<string[]>(allColumns.map((column) => column.field));
  const [filterMenuField, setFilterMenuField] = useState<ColumnField | null>(null);
  const [columnFilters, setColumnFilters] = useState<Partial<Record<ColumnField, ColumnFilter>>>({});
  const [draftColumnFilter, setDraftColumnFilter] = useState<ColumnFilter>(defaultColumnFilter);
  const [currentPage, setCurrentPage] = useState(1);
  const [pageSize, setPageSize] = useState(10);
  const [sortField, setSortField] = useState<ColumnField>('name');
  const [sortDirection, setSortDirection] = useState<SortDirection>('asc');
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const actionMenuRef = useRef<HTMLDivElement>(null);
  const columnsMenuRef = useRef<HTMLDivElement>(null);
  const filterMenuRef = useRef<HTMLDivElement>(null);
  const { getColumnStyle, renderResizeHandle } = useResizableColumns<ColumnField>(defaultColumnWidths);

  const fetchAssetStates = async () => {
    setLoading(true);
    try {
      const response = await getAssetStates();
      setAssetStates(response.data);
    } catch (error) {
      console.error('Error fetching asset states:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAssetStates();
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (actionMenuRef.current && !actionMenuRef.current.contains(event.target as Node) && actionAnchorEl && !actionAnchorEl.contains(event.target as Node)) {
        setActionAnchorEl(null);
      }
      if (columnsMenuRef.current && !columnsMenuRef.current.contains(event.target as Node)) setColumnsAnchorEl(null);
      if (filterMenuRef.current && !filterMenuRef.current.contains(event.target as Node)) setFilterMenuField(null);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [actionAnchorEl]);

  const filteredAssetStates = useMemo(() => {
    return assetStates.filter((item) => {
      if (activeFilter === filterOptions[0] && !item.active) return false;
      return allColumns.every((column) => {
        const filter = columnFilters[column.field];
        return filter ? doesValueMatchColumnFilter(getColumnValue(item, column.field), filter) : true;
      });
    });
  }, [activeFilter, columnFilters, assetStates]);

  const sortedAssetStates = useMemo(() => {
    return [...filteredAssetStates].sort((a, b) => {
      const aValue = getColumnValue(a, sortField);
      const bValue = getColumnValue(b, sortField);
      const result = aValue.toString().localeCompare(bValue.toString(), undefined, { numeric: true, sensitivity: 'base' });
      return sortDirection === 'asc' ? result : -result;
    });
  }, [filteredAssetStates, sortDirection, sortField]);

  const totalPages = Math.max(1, Math.ceil(sortedAssetStates.length / pageSize));
  const startIndex = (currentPage - 1) * pageSize;
  const endIndex = startIndex + pageSize;
  const paginatedData = sortedAssetStates.slice(startIndex, endIndex);

  useEffect(() => {
    if (currentPage > totalPages) setCurrentPage(totalPages);
  }, [currentPage, totalPages]);

  const handleOpen = (item: AssetState | null = null) => {
    setEditing(item);
    setOpen(true);
  };

  const handleClose = () => {
    setOpen(false);
    setEditing(null);
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      await fetchAssetStates();
      handleClose();
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (window.confirm('Are you sure you want to delete this asset state?')) {
      try {
        await deleteAssetState(id);
        fetchAssetStates();
        setActionAnchorEl(null);
      } catch (error) {
        console.error('Error deleting asset state:', error);
      }
    }
  };

  const handleClearFilters = () => {
    setActiveFilter(filterOptions[0]);
    setColumnFilters({});
    setFilterMenuField(null);
    setDraftColumnFilter(defaultColumnFilter);
    setCurrentPage(1);
  };

  const handleOpenColumnFilter = (field: ColumnField) => {
    setDraftColumnFilter(columnFilters[field] ?? defaultColumnFilter);
    setFilterMenuField((currentField) => (currentField === field ? null : field));
  };

  const handleApplyColumnFilter = (field: ColumnField) => {
    const needsValue = draftColumnFilter.operator !== 'Blank' && draftColumnFilter.operator !== 'Not blank';
    if (needsValue && !draftColumnFilter.value.trim()) {
      handleResetColumnFilter(field);
      return;
    }
    setColumnFilters((prev) => ({ ...prev, [field]: { ...draftColumnFilter, value: needsValue ? draftColumnFilter.value : '' } }));
    setFilterMenuField(null);
    setCurrentPage(1);
  };

  const handleResetColumnFilter = (field: ColumnField) => {
    setColumnFilters((prev) => {
      const next = { ...prev };
      delete next[field];
      return next;
    });
    setDraftColumnFilter(defaultColumnFilter);
    setFilterMenuField(null);
    setCurrentPage(1);
  };

  const handleSort = (field: ColumnField) => {
    if (sortField === field) {
      setSortDirection((currentDirection) => (currentDirection === 'asc' ? 'desc' : 'asc'));
    } else {
      setSortField(field);
      setSortDirection('asc');
    }
    setCurrentPage(1);
  };

  const actionMenuStyle = actionAnchorEl
    ? {
        position: 'absolute' as const,
        top: actionAnchorEl.getBoundingClientRect().bottom + window.scrollY + 8,
        left: actionAnchorEl.getBoundingClientRect().left + window.scrollX,
      }
    : undefined;

  const renderColumnHeader = (field: ColumnField, label: string) => {
    const hasFilter = Boolean(columnFilters[field]);
    const isValueDisabled = draftColumnFilter.operator === 'Blank' || draftColumnFilter.operator === 'Not blank';

    return (
      <th className="relative px-4 py-4 text-left text-xs font-semibold uppercase tracking-wider text-slate-500" style={getColumnStyle(field)}>
        <div className="flex items-center justify-between gap-2">
          <button type="button" onClick={() => handleSort(field)} className="inline-flex items-center gap-1 text-left">
            {label}
            <span className={`text-[10px] leading-none ${sortField === field ? 'text-blue-600' : 'text-slate-400'}`} aria-hidden="true">
              {sortField === field && sortDirection === 'desc' ? '\u25BC' : '\u25B2'}
            </span>
          </button>
          <button
            type="button"
            onClick={(event) => {
              event.stopPropagation();
              handleOpenColumnFilter(field);
            }}
            className={`rounded p-1 hover:bg-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500 ${hasFilter ? 'text-blue-600' : 'text-slate-500'}`}
            aria-label={`Filter ${label}`}
          >
            <svg className="h-3.5 w-3.5" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
              <path d="M2 3H14M4.5 7H11.5M6.5 11H9.5" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" />
            </svg>
          </button>
        </div>
        {filterMenuField === field && (
          <div ref={filterMenuRef} className="absolute right-2 top-11 z-20 w-48 rounded-md border border-slate-300 bg-white p-3 text-slate-700 shadow-xl">
            <select
              value={draftColumnFilter.operator}
              onChange={(event) => setDraftColumnFilter((prev) => ({ ...prev, operator: event.target.value as ColumnFilterOperator }))}
              className="mb-2 w-full rounded border border-slate-300 bg-white px-2 py-2 text-sm font-normal normal-case tracking-normal text-slate-900 focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              {columnFilterOptions.map((option) => (
                <option key={option} value={option}>{option}</option>
              ))}
            </select>
            <div className="relative">
              <span className="pointer-events-none absolute left-2 top-1/2 -translate-y-1/2 text-slate-400">
                <svg className="h-3.5 w-3.5" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <path d="M7 12A5 5 0 1 0 7 2a5 5 0 0 0 0 10ZM10.5 10.5L14 14" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
                </svg>
              </span>
              <input
                value={draftColumnFilter.value}
                onChange={(event) => setDraftColumnFilter((prev) => ({ ...prev, value: event.target.value }))}
                disabled={isValueDisabled}
                placeholder="Filter..."
                className="w-full rounded border border-slate-300 bg-white py-2 pl-7 pr-2 text-sm font-normal normal-case tracking-normal text-slate-900 placeholder:text-slate-400 focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:bg-slate-100"
              />
            </div>
            <div className="mt-4 flex justify-end gap-2">
              <button type="button" onClick={() => handleApplyColumnFilter(field)} className="rounded border border-slate-300 bg-white px-3 py-2 text-sm font-normal normal-case tracking-normal text-slate-700 hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500">Apply</button>
              <button type="button" onClick={() => handleResetColumnFilter(field)} className="rounded border border-slate-300 bg-white px-3 py-2 text-sm font-normal normal-case tracking-normal text-slate-700 hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500">Reset</button>
            </div>
          </div>
        )}
        {renderResizeHandle(field)}
      </th>
    );
  };

  return (
    <div className="bg-white rounded-lg shadow-sm p-6 space-y-5">
      <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4 mb-4">
        <div className="flex flex-col md:flex-row md:items-center gap-3">
          <select
            value={activeFilter}
            onChange={(event) => {
              setActiveFilter(event.target.value);
              setCurrentPage(1);
            }}
            className="w-full md:w-64 rounded-md border border-slate-300 bg-white px-3 py-2 text-sm text-slate-900 focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            {filterOptions.map((option) => (
              <option key={option} value={option}>{option}</option>
            ))}
          </select>
          <button onClick={() => handleOpen()} className="rounded-md bg-blue-600 px-4 py-2 text-sm font-medium text-white hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500" type="button">
            New Asset State
          </button>
        </div>
        <div className="flex flex-wrap items-center gap-2">
          <button onClick={handleClearFilters} className="rounded-md border border-slate-300 bg-white px-4 py-2 text-sm text-slate-700 hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500" type="button">
            Clear All Filters
          </button>
          <div className="relative">
            <button onClick={(event) => setColumnsAnchorEl(event.currentTarget)} className="rounded-md border border-slate-300 bg-white px-4 py-2 text-sm text-slate-700 hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500" type="button">
              &#9654; Select Columns
            </button>
            {columnsAnchorEl && (
              <div ref={columnsMenuRef} className="absolute right-0 z-10 mt-1 w-56 rounded-md border border-slate-300 bg-white p-2 shadow-lg">
                {allColumns.map((column) => (
                  <label key={column.field} className="flex cursor-pointer items-center gap-2 rounded-sm px-2 py-1 hover:bg-slate-50">
                    <input
                      type="checkbox"
                      checked={visibleColumns.includes(column.field)}
                      onChange={() => setVisibleColumns((prev) => (prev.includes(column.field) ? prev.filter((value) => value !== column.field) : [...prev, column.field]))}
                      className="h-4 w-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                    />
                    <span className="text-sm text-slate-700">{column.label}</span>
                  </label>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      {loading && (
        <div className="flex justify-center items-center py-12">
          <span className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-blue-600"></span>
        </div>
      )}

      <div className="overflow-x-auto rounded-lg border border-slate-200 bg-white shadow-sm">
        <table className="w-full min-w-[1100px] table-fixed divide-y divide-slate-200">
          <thead className="bg-[#fafafa]">
            <tr>
              <th className="w-12 px-4 py-4 text-left text-xs font-semibold uppercase tracking-wider text-slate-500"></th>
              {visibleColumns.includes('name') && renderColumnHeader('name', 'Name')}
              {visibleColumns.includes('description') && renderColumnHeader('description', 'Description')}
              {visibleColumns.includes('requires_ownership') && renderColumnHeader('requires_ownership', 'Requires Ownership')}
              {visibleColumns.includes('requires_scan') && renderColumnHeader('requires_scan', 'Requires Scan')}
              {visibleColumns.includes('active') && renderColumnHeader('active', 'Active')}
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-slate-200">
            {paginatedData.map((item) => (
              <tr key={item.id} className="hover:bg-slate-50 transition-colors duration-150">
                <td className="w-12 px-4 py-4 whitespace-nowrap text-sm text-slate-900">
                  <button
                    onClick={(event) => {
                      event.stopPropagation();
                      setActionRow(item);
                      setActionAnchorEl(event.currentTarget);
                    }}
                    className="text-slate-400 hover:text-slate-600"
                    aria-label="Actions"
                    type="button"
                  >
                    <svg width="16" height="16" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg">
                      <rect y="4" width="20" height="2" rx="1" fill="currentColor" />
                      <rect y="9" width="20" height="2" rx="1" fill="currentColor" />
                      <rect y="14" width="20" height="2" rx="1" fill="currentColor" />
                    </svg>
                  </button>
                </td>
                {visibleColumns.includes('name') && <td className="px-4 py-4 whitespace-nowrap text-sm text-slate-900" style={getColumnStyle('name')}>{item.name}</td>}
                {visibleColumns.includes('description') && <td className="px-4 py-4 whitespace-nowrap text-sm text-slate-900" style={getColumnStyle('description')}>{item.description}</td>}
                {visibleColumns.includes('requires_ownership') && <td className="px-4 py-4 whitespace-nowrap text-sm text-slate-900" style={getColumnStyle('requires_ownership')}>{getColumnValue(item, 'requires_ownership')}</td>}
                {visibleColumns.includes('requires_scan') && <td className="px-4 py-4 whitespace-nowrap text-sm text-slate-900" style={getColumnStyle('requires_scan')}>{getColumnValue(item, 'requires_scan')}</td>}
                {visibleColumns.includes('active') && <td className="px-4 py-4 whitespace-nowrap text-sm text-slate-900" style={getColumnStyle('active')}>{getColumnValue(item, 'active')}</td>}
              </tr>
            ))}
            {paginatedData.length === 0 && (
              <tr>
                <td colSpan={visibleColumns.length + 1} className="px-6 py-8 text-center text-sm text-slate-500">
                  No asset states found
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {actionAnchorEl && (
        <div ref={actionMenuRef} className="fixed z-10 w-40 rounded-md border border-slate-200 bg-white shadow-lg" data-action-menu style={actionMenuStyle}>
          <button
            onClick={() => {
              if (actionRow) handleOpen(actionRow);
              setActionAnchorEl(null);
            }}
            className="block w-full px-4 py-2 text-left text-sm text-slate-700 hover:bg-slate-100"
            type="button"
          >
            Edit
          </button>
          <button
            onClick={() => {
              if (actionRow) handleDelete(actionRow.id);
              setActionAnchorEl(null);
            }}
            className="block w-full px-4 py-2 text-left text-sm text-slate-700 hover:bg-slate-100"
            type="button"
          >
            Delete
          </button>
        </div>
      )}

      <div className="mt-6 flex flex-col gap-4 md:flex-row md:items-center md:justify-between">
        <div className="flex items-center gap-2 text-sm text-slate-700">
          <span>Page Size:</span>
          <select value={pageSize} onChange={(event) => { setPageSize(parseInt(event.target.value, 10)); setCurrentPage(1); }} className="rounded-md border border-slate-300 bg-white px-3 py-1 text-sm focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500">
            <option value={10}>10</option>
            <option value={25}>25</option>
            <option value={50}>50</option>
          </select>
        </div>
        <div className="flex flex-wrap items-center gap-3 text-sm text-slate-600">
          <span>{sortedAssetStates.length === 0 ? '0 to 0 of 0' : `${startIndex + 1} to ${Math.min(endIndex, sortedAssetStates.length)} of ${sortedAssetStates.length}`}</span>
          <div className="flex items-center gap-2">
            <button onClick={() => currentPage > 1 && setCurrentPage(currentPage - 1)} disabled={currentPage === 1} className="rounded-md border border-slate-300 px-3 py-1 text-sm text-slate-700 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed" type="button">
              &#8592;
            </button>
            <span className="text-sm text-slate-600">Page {currentPage} of {totalPages}</span>
            <button onClick={() => currentPage < totalPages && setCurrentPage(currentPage + 1)} disabled={currentPage === totalPages} className="rounded-md border border-slate-300 px-3 py-1 text-sm text-slate-700 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed" type="button">
              &#8594;
            </button>
          </div>
        </div>
      </div>

      {open && (
        <div className="fixed inset-0 z-50 overflow-y-auto">
          <div className="fixed inset-0 bg-slate-900/25" aria-hidden="true" onClick={handleClose}></div>
          <div className="relative mx-auto mt-14 w-full max-w-2xl rounded-3xl bg-white p-10 shadow-2xl">
            <div className="mb-5 flex items-start justify-between">
              <h2 className="text-2xl font-semibold text-slate-900">{editing ? 'Edit Asset State' : 'Add Asset State'}</h2>
              <button type="button" onClick={handleClose} className="inline-flex h-10 w-10 items-center justify-center rounded-full bg-slate-100 text-slate-900 hover:bg-slate-200" aria-label="Close">
                <svg className="h-4 w-4" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
                  <path d="M4 4L12 12M12 4L4 12" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" />
                </svg>
              </button>
            </div>
            <AssetStateForm editing={editing} onSave={handleSave} onClose={handleClose} saving={saving} />
          </div>
        </div>
      )}
    </div>
  );
};

export default AssetStateTable;
